const char* getNamedResource (const char* resourceNameUTF8, int& numBytes);
const char* getNamedResource (const char* resourceNameUTF8, int& numBytes)
{
    unsigned int hash = 0;

    if (resourceNameUTF8 != nullptr)
        while (*resourceNameUTF8 != 0)
            hash = 31 * hash + (unsigned int) *resourceNameUTF8++;

    switch (hash)
    {
        case 0xb3e40b64:  numBytes = 39464; return Noise_png;
        case 0x3dff11ef:  numBytes = 18673; return plugintitle_png;
        case 0x8c6159e8:  numBytes = 69058; return testir_wav;
        default: break;
    }

    numBytes = 0;
    return nullptr;
}

